#include <stdio.h>
#include <string.h>

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char s[100005];
        int K;
        scanf("%s", s);
        scanf("%d", &K);
        int n = strlen(s);
        char st[100005];
        int top = 0; // size of stack
        for (int i = 0; i < n; ++i) {
            char c = s[i];
            while (top > 0 && st[top-1] > c && (top - 1 + (n - i - 1) >= K)) {
                --top; // pop
            }
            if (top < K) {
                st[top++] = c; // push
            }
        }
        st[top] = '\0';
        printf("%s\n", st);
    }
    return 0;
}

