#!/usr/bin/env python3
import sys

def smallest_subseq(s, k):
    n = len(s)
    stack = []
    for i, c in enumerate(s):
        while stack and stack[-1] > c and (len(stack) - 1 + (n - i - 1) >= k):
            stack.pop()
        if len(stack) < k:
            stack.append(c)
    return ''.join(stack)

def main():
    data = sys.stdin.read().splitlines()
    t = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(t):
        s = data[idx].strip(); idx += 1
        k = int(data[idx]); idx += 1
        out_lines.append(smallest_subseq(s, k))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

